import os
import shutil
import hashlib
import mimetypes
from datetime import datetime
from pathlib import Path
from typing import Optional

from fastapi import FastAPI, HTTPException, Query, UploadFile, File, Depends, Header
from fastapi.responses import FileResponse, JSONResponse
from pydantic import BaseModel

app = FastAPI(title="File Explorer API")

# Base directory where all user files are stored
BASE_UPLOAD_DIR = os.path.abspath(os.path.join(os.path.dirname(__file__), "user_files"))

# Ensure base directory exists
os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)


def get_user_root(user_id: str) -> str:
    """Get the root directory for a specific user."""
    user_root = os.path.abspath(os.path.join(BASE_UPLOAD_DIR, user_id))
    os.makedirs(user_root, exist_ok=True)
    return user_root


def resolve_safe_path(user_root: str, relative_path: str) -> str:
    """
    Safely resolve a user-provided relative path to an absolute path
    within the user's root directory. Prevents path traversal attacks.
    """
    # Normalize the path to handle '..' and other path components
    normalized = os.path.normpath(relative_path)

    # Construct the full path
    full_path = os.path.join(user_root, normalized)

    # Resolve to absolute path
    full_path = os.path.abspath(full_path)

    # Security check: ensure the resolved path is within the user's root
    if not full_path.startswith(os.path.abspath(user_root)):
        raise HTTPException(
            status_code=403,
            detail="Access denied: path traversal detected. The resolved path is outside your root directory."
        )

    return full_path


def get_current_user_id(x_user_id: str = Header(default="default_user")) -> str:
    """Extract user ID from header. In production, use proper authentication."""
    # Sanitize user_id to prevent path traversal in user directory names
    sanitized = os.path.normpath(x_user_id).replace(os.sep, "_").replace("..", "_")
    if sanitized != x_user_id or "/" in x_user_id or "\\" in x_user_id:
        raise HTTPException(status_code=400, detail="Invalid user ID")
    return sanitized


