def get_file_info(full_path: str, user_root: str) -> FileInfo:
    """Get detailed information about a file or directory."""
    stat_info = os.stat(full_path)
    relative_path = os.path.relpath(full_path, user_root)
    if relative_path == ".":
        relative_path = "/"
    else:
        relative_path = "/" + relative_path.replace(os.sep, "/")

    is_dir = os.path.isdir(full_path)
    mime_type = None
    if not is_dir:
        mime_type, _ = mimetypes.guess_type(full_path)

    return FileInfo(
        name=os.path.basename(full_path) or "/",
        path=relative_path,
        is_directory=is_dir,
        size=stat_info.st_size if not is_dir else None,
        created=datetime.fromtimestamp(stat_info.st_ctime).isoformat(),
        modified=datetime.fromtimestamp(stat_info.st_mtime).isoformat(),
        mime_type=mime_type,
        permissions=oct(stat_info.st_mode)[-3:],
    )


@app.get("/api/files/list", response_model=DirectoryListing)
def list_directory(
    path: str = Query(default="/", description="Relative path to list"),
    user_id: str = Depends(get_current_user_id),
):
    """List contents of a directory."""
    user_root = get_user_root(user_id)
    
    # Handle root path
    if path in ("/", "", "."):
        full_path = user_root
    else:
        # Strip leading slash for os.path.join to work correctly
        relative = path.lstrip("/")
        full_path = resolve_safe_path(user_root, relative)

    if not os.path.exists(full_path):
        raise HTTPException(status_code=404, detail=f"Path not found: {path}")

    if not os.path.isdir(full_path):
        raise HTTPException(status_code=400, detail=f"Path is not a directory: {path}")

    items = []
    try:
        for entry_name in sorted(os.listdir(full_path)):
            entry_path = os.path.join(full_path, entry_name)
            try:
                items.append(get_file_info(entry_path, user_root))
            except (PermissionError, OSError):
                continue
    except PermissionError:
        raise HTTPException(status_code=403, detail="Permission denied")

    # Calculate parent path
    relative_path = os.path.relpath(full_path, user_root)
    if relative_path == ".":
        current_path = "/"
        parent = None
    else:
        current_path = "/" + relative_path.replace(os.sep, "/")
        parent_rel = os.path.dirname(relative_path)
        parent = "/" if parent_rel == "" else "/" + parent_rel.replace(os.sep, "/")

    return DirectoryListing(
        path=current_path,
        parent=parent,
        items=items,
        total_items=len(items),
    )


